 * These are mentioned to not be stable and may change in the future. Doubtful, but possible.
 */
export type NetcheckResponse = {
  Now: string;
  UDP: boolean;
  IPv6: boolean;
  IPv4: boolean;
  IPv6CanSend: boolean;
  IPv4CanSend: boolean;
