export type DerpRegion = {
  RegionID: number;
  RegionCode: string;
  RegionName: string;
  Latitude: number;
  Longitude: number;
  Nodes: DerpNode[];
};

type DerpNode = {
  Name: string;
  RegionID: number;
  HostName: string;
  IPv4: string;
  IPv6: string;
  CanPort80: boolean;
};

export type Derp = {
